, "20": 50, "21": 50, "22": 35, "4": 0, "5": 35, "6": 42, "7": 57, "8": 57, "9": 71}, "Tuesday": {"10": 64, "11": 78, "12": 85, "13": 64, "14": 71, "15": 71, "16": 64, "17": 57, "18": 42, "19": 42, "20": 57, "21": 57, "22": 42, "4": 0, "5": 85, "6": 57, "7": 50, "8": 35, "9": 42}, "Wednesday": {"10": 42, "11": 42, "12": 28, "13": 35, "14": 21, "15": 28, "16": 21, "17": 14, "18": 21, "19": 21, "20": 28, "21": 35, "22": 42, "4": 0, "5": 28, "6": 50, "7": 85, "8": 100, "9": 71}}'::jsonb, NULL, ARRAY['Adaptive sports center'], NULL, '05:00', '23:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('CHƠI Pickleball Club FPT', 'Khu đô thị FPT City, Ngũ Hành Sơn, Đà Nẵng 555555, Vietnam', 'Da Nang', 'Khu đô thị FPT City, Ngu Hanh Son', 15.97149, 108.264528, 4.8, 67, '+84 852 259 597', 'https://www.google.com/maps/place/CH%C6%A0I+Pickleball+Club+FPT/data=!4m7!3m6!1s0x3142115ef80c964d:0xe0d372d7dfad0f8b!8m2!3d15.9714905!4d108.2645282!16s%2Fg%2F11x698g9f8!19sChIJTZYM-F4RQjERiw-t39dy0-A?authuser=0&hl=en&rclk=1', NULL, 'ChIJTZYM-F4RQjERiw-t39dy0-A', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFzHJ_1sPpBQVGVOlAlS7N4qpYVQHlnDE04v3Z7BB4lnpqMpq6qzp2lO_HdbP9oxjGwVaA6EeDrTuGGrV0nHnV0H6oj-PhZyYmV4luEcpYxG8xXejNvDFqUQ6XE-FmJtoPLh9xNnZ9TAOee=w426-h240-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFzHJ_1sPpBQVGVOlAlS7N4qpYVQHlnDE04v3Z7BB4lnpqMpq6qzp2lO_HdbP9oxjGwVaA6EeDrTuGGrV0nHnV0H6oj-PhZyYmV4luEcpYxG8xXejNvDFqUQ6XE-FmJtoPLh9xNnZ9TAOee=w529-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAF6XrzJZktwej8UZPxalZEB5ifRaCBTwZ7EiMHy9XOAF6atO7unZBuV-FuYSisxiVIm4MUX_lZSpK_Sfu5jbra5A2S8wJQsgAUn54ZXmSrJpPcCpIHRx-ljHfiTMoUuRmc4XUuJS0NQpLjE=w224-h398-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFpr9HX5RtE6j66bdh5TaPxI-m5sz82GKpIM2y4Q-KK4Gnmj_h_FwrdZe8PLUy34T1TooAMhPyhNRrMEX4Nt9OE8hEaKNm8Bcf90IWXqzJ5nYe-elQQO1jSQPcMZbcy1Jl2AhzH=w531-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=ocUC4fqSq8Rk8DhMe4bzbA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=339.94473&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5:30 a.m.–9:30 p.m."], "Monday": ["5:30 a.m.–9:30 p.m."], "Saturday": ["5:30 a.m.–9:30 p.m."], "Sunday": ["5:30 a.m.–9:30 p.m."], "Thursday": ["5:30 a.m.–9:30 p.m."], "Tuesday": ["5:30 a.m.–9:30 p.m."], "Wednesday": ["5:30 a.m.–9:30 p.m."]}'::jsonb, '[{"Name": "Angel Trinidad", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU71fvyIvbRt7AYWu2zIcdjYPqT26SWy-XdQMMwn6ioxLZ4f05b=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Came here by myself around 530 PM which was perfect time for their open play. Everyone was very friendly and welcoming, they invited me to play with them and if they could keep score in English for me they did. I don’t speak any Vietnamese so it was very nice of them to still make me feel welcomed.\n\nSon who works there helped me at the front and let me rent a paddle. The courts are well maintained and very dry even in the rain. There is also water, other drinks and ice cream for sale. I am definitely coming back again!! Thanks Choi Pickleball Center for a super fun time!\n\nOpen play times are below. Three hours of play for fee of 30,000 at the time of this post!\n\n6:30 AM\n11:30 AM\n5:30 PM\n\nThey also had free WiFi which came in clutch for me to get a Grab back to my place!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3ffylAXDdmeZUECqIbdUogt6Ic2FdwpRnWuhAhn3uL2HhzIvdAoxvi3fduy4_9ftY6DWlIOpYTqrF3rvH9c9HbE-W9mKrWxMdHlxBA0v531MKi9U_ZlwTIAkjN0uI89hZetWN_OaDq6uja=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1Mxa8Ct_-bmbJ-KDP8gYOfAcCtuV7a3rgANHiIn8kNrC8kXGpelMKa_z6ncUvV8O7P4IMZc-NOr1OqI-mmwrhLzBBq54VeiPNSb4JI4EdaNXv6Tur2TBdxPOeCfasgreAXTQNbWy5j_THX=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0w1Wlol3Mhb4E8NPPs-aa4L8xs-Yo5xIEm8tlCc_exoNNnffbjg1uqw03rTL-fwO6HgWYRou86YqJI3oLGzeYnVzBgjxyzIu9PyYAfjsTReXMCp1BhV0Q11nc_SBrdm5catv4jAcpiQgm6=k-no"], "When": "2026-1-7"}, {"Name": "Elsie M", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJ36HPRE3rhgK_PuNkLX6Da0lSs_BJ4zIVsJopUAMAvFg3fIQ=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "I loved this place!! It was close to the hotel, very fun. We got the courts originally to play skinny singles but little by little others showed up and we got to play a lot of doubles. Right as we were leaving, open play was starting and a lot of people started coming. Definitely a great facility.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0JsE1OhnbgqouMj3v76R61s0Ny2xPvtS-psr_HPDJjt9hVEDc7WbGdH_PYcJCpkIrief38FKBdvENfwf95PvBMvuz_TifUpD2TjBX5aKTL1K2C1FaOWz-QJ7iWCYO1nu6VGkEMat2WBOa5=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2otuHYeP8dN2mUqGofBxjlBv_c-ptcs7owtXr_4PtLC-JpFoClmqzUmegYGtGLHIZ5367t0iLXGkOWownWC-jfZbSjvXIfHKvRGsR0JjAAHs-hDAxllHhVGtaSV3wGglVYsA8Qn2axgV_9=k-no"], "When": "2025-9-18"}, {"Name": "Jermaine Hankston", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUQHFTFKInCqjohiXnifiDhRqsaX8jzfZ3wE7RZrQ32E-71rLM=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "This was a deeply disturbing experience. The pickleball instructor was rude, disrespectful, and showed clear racial bias toward me and my family as Black patrons. What made the situation worse is that he attempted to film us and tried to get us to repeat words in Vietnamese that we later realized were racial slurs without telling us what we were saying. This behavior was completely inappropriate, offensive, and unacceptable. No one should ever be treated this way, and management needs to address this immediately to ensure this kind of conduct never happens again.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0INk8eFAIQmrZwys6DywjAdM0c5ZHbkAaD6RtwMe_8Mx_achUES2RM6t9Au95aJWxQ08Kikj8QXnz1juXG20M8XLHgBSY_oVvmevplKpvmYQMt-4qINihMi54bMzFjN-7RNfmJmXXAD-AG=k-no"], "When": "2026-1-30"}, {"Name": "Bradley Tyberg", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXhQ-qtMXgfxncjgFNPLnhrK1OsrpyTlecbTccKV6Tc1YfTE-VA=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Best pickleball court in Danang! Great facilities in a great location with cool bar/cafe!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2DIQxhXyrwKr4WxIgSNK1Asqv6-_U4ROZOHAQmeAAsvgFmUrLMGHVpLMWtZ23ccJo1jmUGvWpwaGD_t16hnFGk26acgDeONYqAOpdc6XFNhu14cUwcEjdYGcS2-q1nm2tWV-x7=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0Zib7144E0OrL6itNYEQJJY8aGWGyOgmzHJ8bKN_XDYFTW49pSUvW17VFJ1m8PAxbJVyHxbYnWY9rEnjKguVlkwdZJsFDVN8re_AOHFxhs9O274RD6a1q4qov0qolMoKhDph1N=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3iLjSnrNW_U4tgmJBcxD4srn_38h6e8-jVBEWcdpqm5QvHjYqExQLuaBIrlJ8iYM-nY6h-zznBEsbElonbjAw6VZHeik0s8aL2BKSgW1-qngqEGTU6HWteDoYo9CVbbDDxhB7c=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn22dX8guAGI4x_evX2cTg0rhNeKHX3rQ9qqPJTVE3yINjhUoXAlBc-9hCl6QS7UDe6wTJQDZY-_MiC-gT8FhrtrfRR1C-cuy53yCemt62Dv0X5DDWHodhAiSPw4oLDXtu4bQTBw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn05RUYHMlszYejGGG1Yt08kKf8L-maZxNYX_lho-kAj3mmLIobc1Ieo00diOhP2rc48sDpyTaslSEcVGEk5_GAwhMCmrSm-36nBEc03h2dB2oQQByMr12g6xW0ZvkQKK0D3FCxGvw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn19qSSt9odHqcNz3e7AiAbtgbmiQOGiqtL3YOraKBiF_uCF6CB37Hiuv4HRCX6dpkqtbn__5MViKtNJ_J3azURBlAfXU5RHOTo88c3AbBxc4COI7RvUFAxmcRLSIhCYNrGwbaStsA=k-no"], "When": "2025-6-12"}, {"Name": "Giang Bui Trong", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLCGnqLXckfjdef7fcxJctEOxXS2kBkIE0EylxBtswQ06S1sA=s120-c-rp-mo-br100", "Rating": 5, "Description": "A 6-court indoor & outdoor complex is located in a prime location just half of mile from beach resorts, hotels and best golf courts.\n\nGood quality court foundations and proof tents plus clean restrooms , especially you guys have a spacious garden area chilling out with music and beers after enjoying games.\n\nThe most impressive points is the host enthusiasm and his team mates good services.", "Images": null, "When": ""}, {"Name": "Nam Do", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWSPAw4fSzodQx2VeM2hvyWzv5YJoSBBRmFoGqqAaJEBbaNB2Xq=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Very fun place to play pickleball. I highly recommend!", 