LUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Pickleball Hội An', '122 Lý Thường Kiệt, Sơn Phong, Hội An, Đà Nẵng, Vietnam', 'Da Nang', 'Sơn Phong, Hoi An', 15.881384, 108.33701, 4.7, 41, NULL, 'https://www.google.com/maps/place/Pickleball+H%E1%BB%99i+An/data=!4m7!3m6!1s0x31420d004d34b50f:0x736f5dba121815b4!8m2!3d15.8813838!4d108.3370098!16s%2Fg%2F11wh9pr4kd!19sChIJD7U0TQANQjERtBUYErpdb3M?authuser=0&hl=en&rclk=1', 'https://www.facebook.com/profile.php?id=61567127755727&mibextid=LQQJ4d', 'ChIJD7U0TQANQjERtBUYErpdb3M', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAHIt9DcGHRFRjmnpLn7HXxAfyjztp1YVrJwSIaJqD0asjSslkzVi5L7FeV03eTvsvYk9dMNn_sH26u9F8JgxKLJLhzCRu_iGooW3O7Y8JjSHkiYQmx5HiH_booMj7II1l9pUbehATLbwVDq=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHIt9DcGHRFRjmnpLn7HXxAfyjztp1YVrJwSIaJqD0asjSslkzVi5L7FeV03eTvsvYk9dMNn_sH26u9F8JgxKLJLhzCRu_iGooW3O7Y8JjSHkiYQmx5HiH_booMj7II1l9pUbehATLbwVDq=w397-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGPr3HIwU1cBmc_sGFndaSZHzE-ScG-_ar3kl69a3IiAAN8dUJ3gxSMVqOap1vQlk7iSRHKBPdRmfYzjhmyALuqC-KUK3oRDsBWJwM2TDO3nIiHIszl5Z2oICtitlJEONZfXaowmg=w590-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAF576AgTeqlbNvoCqmRTXGhop5deIQzn0nX1_gu0RXeHnLxxyOWsvrnpKsKplZXOPiZyATbnbUAF8cfQOZGYuYqEHmYaRj936vEL3bqdBMoscGXqy5PqVt44shRko8a-43c2R8BAA2Y7LUP=w224-h398-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=Hj1WzjDjpzM3JyMPr6uyMw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=11.390045&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–8 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "dawido", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWJhSjEHcddFScwRH-uzIHqNxO0AO3HcIWRlJEIBvF-s9DW4dm_=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great facility, I highly recommend if you want to play some pickleball on the down time. Indoors, cool and quiet; my girlfriend and I played a good hour and had a lot of fun. Thank you. The owner is a lovely lady also, she was very kind.", "Images": null, "When": ""}, {"Name": "Libby S", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLvhVDO__5JQo3MJSnuPu1d45AH3uVpwUqxsGPmToOr_A_u4A=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "We walked past and decided we would try out pickle ball for the first time. We booked for a couple of days time, the courts are well built, shaded and pretty private which is good if you don’t know what you are doing. This was very reasonably priced - we paid 135k for an hour (£4.30). Great, fun way to do some exercise while travelling. I would recommend (take some water and check the rules before going if it’s also your first time!)", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1gdsCceLYFdkEeYxomQ1Lt1fojyQ0_YgR-A9GQevc3ZZWvcMPuFDKp9slHlwDRhTpOyTHch178S_djtKtfwiqdrJQHgqcMpu2Mcozwgn_tei9laW0flbkp-xQLllRdt68WuM39SQ=k-no"], "When": "2025-1-31"}, {"Name": "gctseng gmail", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocI-WhsoVo0LLDbC7BFpYsE-JsTmd4wUwfNmZe6PfX0yRaNvEyok=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Review - Pickleball Hoi An\n\n122 Lý Thường Kiệt, Sơn Phong, Hội An, Quảng Nam, Vietnam\n\nThis is as much of a review of Pickleball Hội An as it is an observation about my wife. We arrived at a little past 9:10AM and, because we don’t speak Vietnamese, originally we had some communication issues (until I used Google Translate, which helped a little). We had wanted to play for an hour, but the lady said neither of the 2 courts were available until 11:30AM and I was disappointed because we had a tour planned for 10:30AM.\n\nAs I turned around to leave, despondently, in swoops my wife and somehow she and the lady figured out that we could at least play for 1/2 an hour! We were told ₫100,000, which turned out to be a misunderstanding because it was only ₫50,000 for a half-hour.\n\nNice, clean courts with fairly good spacing, although I feel there could be a little more room at the baseline.  They provide equipment and balls.\n\nOne tip is that their entrance is actually through the alley, and not on Lý Thường Kiệt. We actually almost walked into someone’s house before going into the alley next to the house.", "Images": null, "When": ""}, {"Name": "Marco B", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJmcSa_Vy3WD0DqTcJHL8cxgcNYgERgrdqk-t7WdtjE1B47Xwo=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "We had a great time at Pickleball Hội An! The staff is very kind, and the courts are clean and well-maintained. There are also clean bathrooms and a shower with soap available for use after playing. I highly recommend stopping by for a game if you’re in Hội An!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3J4XTldpELR7UQKKpAc8vIdvgUPHkJZjMUvqZPnbj1Iv_cEug0GhootdAZJe_AVC6yb0_e5APmptN4wU5bk7NheFuztAjVtFYGwYkUPk-QQu7ZVaHgFwD9lMgAuVviMIrfyZ6H=k-no"], "When": "2025-5-9"}, {"Name": "Jude Wheatley", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXKYCXx5EK01IQpvIMCM1nsGiUS85euoh5gCJ2Zeqe6QcNh4ntE=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "First time playing pickleball and had so much fun. Its covered from the rain, so a great option for a rainy day and the courts are well maintained. Really reasonably priced aswell!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2ZALMbeNvkju9gXTA3sBaUol2mjp-BFGuPzjm1g7jOXPc5wVhURlGq6B0RdRSsMEUR9QxB_0Dxp1u6PvKixm3bCLOAi3VLXA08UnWHXK7SBNuFUumtov1A8GYgfEtH9VffOqz4HTVBnwpO=k-no"], "When": "2025-7-25"}, {"Name": "Merry", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKxa6dXaO3d39BF5VXSVOBlDsoR4r0QY9PPPCrBdigrsXJRaYyA=s120-c-rp-mo-br100", "Rating": 5, "Description": "What a great spot! Courts are reasonably priced (100/hr). Staff is lovely. They open around 7 though…not 5am.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn224IcPw4G0jZPXeO8RJGLryRD97zxZHORFKbjBGdkLVc2TS232PlO7XVfS7E2YMrdsNKnuzpoFjyqlRRUtGKnkKwtUyFF6QBV0peOZ1a5DZe0rf9-8ueT9AeDICWYSqv91x7JsbA=k-no"], "When": "2025-4-11"}, {"Name": "Caglar Kepenek", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjW6AQNwnF7mc7eCWjSFBpIlpKq4VFlfggFttW5YyAQm1fethgkw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "We had an amazing time at Pickleball Hoi An! The owner and her family were incredibly kind and welcoming. We got a court right away, and they provided paddles and balls, which was really convenient. The court surface was excellent, and the pricing was very reasonable. We’ll definitely be back to play more!", "Images": null, "When": ""}, {"Name": "Keith Hall", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU2ktQBP_yimCf8n0fQr5aOJId9XoiNLhlBMhoXswJr0EijgiiI=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Very nice pickleball centre in Hoi An with great courts and great staff. We were made to feel very welcome. 5 star review from us.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3Q6VJ-1QEv1hh4R332eVWO9dLQxP2NNSv7nb156KNPvL1CPfqA90T8QRx6pwaPSwaU7tIwT49aYSpuj2avsmXLzjudHMhTGPNe98MmFy-azi0eciDHwS41-5z4IrByu2pzbqPG=k-no"], "When": "2025-1-31"}]'::jsonb, '{"Friday": {"10": 42, "11": 38, "12": 26, "13": 26, "14": 26, "15": 38, "16": 50, "17": 57, "18": 73, "19": 92, "20": 80, "21": 50, "4": 0, "5": 11, "6": 26, "7": 61, "8": 65, "9": 65}, "Monday": {"10": 57, "11": 38, "12": 38, "13": 38, "14": 38, "15": 38, "16": 30, "17": 34, "18": 38, "19": 38, "20": 38, "21": 50, "4": 0, "5": 26, "6": 42