INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('The Club House Pickleball HoiAn', '20 Bà Triệu, Phường Cẩm Phổ, Hội An, Đà Nẵng 53000, Vietnam', 'Da Nang', 'Phường Cẩm Phổ, Hoi An', 15.882599, 108.324433, 4.8, 35, '+84 932 500 268', 'https://www.google.com/maps/place/The+Club+House+Pickleball+HoiAn/data=!4m7!3m6!1s0x31420ffecc400199:0xbbd6a6a6bbe98398!8m2!3d15.882599!4d108.3244328!16s%2Fg%2F11lf43cp50!19sChIJmQFAzP4PQjERmIPpu6am1rs?authuser=0&hl=en&rclk=1', NULL, 'ChIJmQFAzP4PQjERmIPpu6am1rs', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGz0XlBiXx5nfqLkNH9ueMJG6iLUB9RNS24ynOyqG0bdegFoxzG66W8DsuxAYcmwbaQqN0YfQkmWXy_4JLVxWb985gjfWsM0Azxp6nRg-j130gSV0d8AgqSs3HJtCNfHEPflJcAeHuefR3q=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGz0XlBiXx5nfqLkNH9ueMJG6iLUB9RNS24ynOyqG0bdegFoxzG66W8DsuxAYcmwbaQqN0YfQkmWXy_4JLVxWb985gjfWsM0Azxp6nRg-j130gSV0d8AgqSs3HJtCNfHEPflJcAeHuefR3q=w397-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGeJLM4v13NwKq5yiCGink5JiKAzpvzMD6-Qwk46RbTGPayIRHum6mfvfKVvWaJSYZpOD2QCzeP3Oqb5f5e6UoId90V-EPZcgSjVgl_RoYyaLreowDCy1M-kn-kG0kEFGhxnXYpDMmWfPc7=w353-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGyFX2D_4qsORQ1eTeIJARe6N6WjOI1ZWrqICjApXm8o0i6Wu-GnFmbre4l55KTbfmV0WzszDYrLTA2OkHYckRjpAj1UkxdddbWfl1qpZlpSJgYG_aiiHGU_P9180AJmxN9YrZJ=w224-h398-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHeJKSmgabBpnjugx6n-lQoHrr_FtALQmwgqzO8KdP9borZEdquAY-dWJllZBvYgIffESW0KN_mtK0_GR7q91sYYr-qOGDHKXdnjt5TeErXhbc453rNDPWslwwKmhyqfoB_AGBR=w397-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=0LBG2bd8vIL9Pp4qa8CRNA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=119.66397&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Sabina", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX62XyVGFQUDTOb277fpcXbPUFxtC672WYF8UPHWoyrb-IYjDQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "Such a welcoming place to play. The local skill level is high, but don''t let that deter you. I received such a warm welcome and friendly, competitive games.\nYou can only shop so much in Hoi An, so come out and play, meet other travelers and locals doing something you enjoy!  You''ll likely pick up a few good tips on restaurants, etc.\n\nIt is well worth it and added to my stay in Hoi An tremendously!\n\n5 stars.\nCourts are incredibly maintained, well built, showers available, covered roof that opens when the sun goes down. Great lighting.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3Ozu_iVEjTTHoPz7P3DOu1SLHQgsqPN2PxRG_45_jBvxsoS55mVgyL_47mgJUA-8FblGgO5m7EL9VJ1U8LzxnAavme632j5ftrwTjof262VseACZo3UG-ZWSg2_tk3ofAUZ58th0fHpdbC=k-no"], "When": "2026-2-5"}, {"Name": "Mary Cooper", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVjgiY29S2rbO0cxRkQ8KhrqrgTyVkN1Cwb7oD_ln_6ULd3s6TCaA=s120-c-rp-mo-br100", "Rating": 3, "Description": "Disappointed.\n\nWe are pickleball fans who are traveling as a couple. We read from other reviews that we could book a court here and ask for a couple other pickleball players to make up a game. The consierge at our hotel called and was assured that this would happen. But when we showed up at the reserved time, we were told that no one was available to play with us.\n\nThere was a coach practicing with two young ladies on another court. We asked if he could coach us after he was done -- but he said he was too busy.\n\nWe hit the ball back and forth between ourselves for awhile, then asked the young ladies (who were somehow affiliated with the club, since one took our payment) if we could have a quick game when they were done. But no, they said they were too busy.\n\nSo all in all, a disappointing experience. One quick game with someone -- anyone -- would have saved the day. But no.\n\nOn the other hand, the price to rent the court/paddle/balls is reasonable (150 dong/hour) and the courts are beautiful. We wish we could have played there.", "Images": null, "When": ""}, {"Name": "Michael Nolan", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXdomnvSMplUeNt-feXuBMccfEipvqA41Msr68XKmvX2ekai1SQuw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Myself and my partner visited in February. We were staying in Hoi An for 5 nights and just fancied an afternoon doing something different and getting a bit of a workout.\n\nWe enquired with the staff in the morning and booked the court for early afternoon. It cost us 150,000 VD (less than £5) for an hour of play. This included the paddles and ball.\n\nThe facilities were great and we really enjoyed ourselves. Would recommend to anyone visiting!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn28xPnuOgLSTyWKASFC5ZZwEw-LLnyvHLAxBReN3SGAxW5adJ0p-62oDTHiPEjln5Ph1K7GJNBizoOB9aHZn4o2OsPnjueK9CLdapS2CTM95XrD6O5Lkp5vA-etpOdXGysfa5iM=k-no"], "When": "2025-4-9"}, {"Name": "Brian Rychlicki", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL07v7_sRQ2pm5NgVPrlUjkLocCHuauwjoe1W8cCQy9cMBjbw=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "This is an amazing pickleball facility in downtown Hoi An. Within a short walking distance of the main tourist area.  The courts and clubhouse are great and you can even get paddles to use if you don’t have one to play with. balls are supplies and the staff are friendly. The roof open and closes based on weather.  I play at a higher level and contacted the owner/manager Hung who was able to set me up with some great play with the locals including himself.  The locals were very good but were also extremely friendly and fun to play with. There were lots of people playing at all ages - young and old, beginner and advanced and the place was full of alot of positive energy.  I highly recommend you visit this place. Also lots of restaurants right next to the courts if your group wants to have some drinks or food.  I played there about 6 times in February 2025.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2TlzSP0aN2K2ETjWbLOAUsruAPIfJ3N5DKFoU285s1ue9RgqgpZeLU6RsTLU0x1Gs2tDVWIv0hEvEUsdJ0B0X1ubz1zFh2zHWUHBYGfC2s0Z3Q-5mwWwH6Ck_4t9bfOvWgt64S=k-no"], "When": "2025-3-26"}, {"Name": "Julian Gilbert", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWurZ2GXuYZJRtLlXy9eSBShbSPy3P0YG8mY_fD7Xp-3DKw6qCpyw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Great spot to get some exercise in while on vacation. Balls and paddles included in court rental is key. Courts are covered by awning which help protected from the elements.\n\nWe called ahead for reservations to the number in the google profile and our courts were booked without issue. Highly recommend!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0EJdssi_4G--I-KZ9Pi7bOHbcmt-Ba3iHrxv8n9a1GVMj7gM6upSNkucAs9JPdXJYqHirl-xTyCIqisvEiLf04ESjlTkKGkF-nFhsgEXdePqzkQ_FnerQHcbaRJxlDPIzH_srd=k-no"], "When": "2024-9-18"}, {"Name": "DT", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJ3YBT0hRfpHQ4R4XC1x5XXT9Y-wwAH19IKJb9Q9xa9ZIyDCbc=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "150.000 dong for one hour. Paddle and balls are included. In the morning it was empty but in the evening you should definitely book beforehand.", "Images": null, "When": ""}, {"Name": "Gordon-James", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXtL0qcToMDxLgImfrPBUILC3UlYIT06ofGhDl8uYybGIxzFk8=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "What a great place to play pickleball in the heart of Hoi An. Better still owner Hung Le and his staff made us feel so welcome! We loved playing here and will definitely be back when next in Hoi An! Highly recommended!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3snmA3Yp5RFKYXskv1FfKhov7EydpzVqtNNskYME2WqW4G7yoQvWZZQRe7mQKy4L1uVSS7DBuU-0XzoT_BPZiCh1rcJhuMY2e7d9RXLBMSOUNjltH3m5nGN6bzVdMFVri5GytG=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3W4O8156dLPAh9u4GTySP4wJ1TCvS66giuvJqOak6JZWyhMuCe9JgF1IApAt_DinFHe_wUE6bneq5skmeNOxOgclguz57tRbuQvkwDvi3cU6uxNv2-GtmVmoxtljqQ7opMtx8FPw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0TD5X7Zg7Rc7KSMg5qvqy5bhesYgnoF3E3DUkJLvTjQJZMwLH2OWEeXhJIIa7bgPQlJ-n3yped6lSfVroBoVsuJYQ9l3rxl_-50QmB9zAzIdbPNNfYVtyY_AYz2VONWnAsLb48=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0tP2xNjYyl-MxJqUxVMBnShaxLwCU4xqFWRcSUbPOwa3mRdY4fnhfgHA7-Py9n4Tz5_7AxsWltt8jFaRKverSfBiTxKAq1x8DRJcXDhFJ2WJAV-X9aPA_Nl-rLXN3OO8qCiHYg=k-no"], "When": "2025-3-25"}, {"Name": "Grete Gessler", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU0fiFgAVnzcbM4pKIRkxNh02L5EGfvFvA1lWkYTUE2aEv_8KI=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Really nice pickleball courts ! It seems pretty new so everything is in great condition.\nKind of busy so I would recommend to Reservate a court in advance (100k deposite). :)", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0_Rv2fnj4QnFCFwGVT9KvY4lzNfEghlItUDSSrFpFDz-FwYSFGcXqDdI8OsFGfjFG5KYTb4bXRY_Me6awG9HE8JQnotzufhREkZlqZUxYqu-Q9dOvkC-nYwyHg06zHr67NAHM=k-no"], "When": "2025-1-4"}]'::jsonb, '{"Friday": {"10": 42, "11": 26, "12": 26, "13": 26, "14": 42, "15": 42, "16": 53, "17": 65, "18": 80, "19": 61, "20": 46, "21": 30, "4": 0, "5": 42, "6": 34, "7": 46, "8": 46, "9": 50}, "Monday": {"10": 30, "11": 38, "12": 38, "13": 42, "14": 42, "15": 34, "16": 30, "17": 26, "18": 26, "19": 26, "20": 30, "21": 23, "4": 0, "5": 23, "6": 23, "7": 30, "8": 34, "9": 42}, "Saturda