aturday": {"0": 57, "1": 35, "10": 57, "11": 64, "12": 85, "13": 64, "14": 42, "15": 28, "16": 21, "17": 28, "18": 35, "19": 42, "2": 42, "20": 50, "21": 50, "22": 57, "23": 50, "3": 42, "4": 42, "5": 35, "6": 14, "7": 14, "8": 21, "9": 35}, "Sunday": {"0": 71, "1": 50, "10": 64, "11": 50, "12": 35, "13": 35, "14": 71, "15": 78, "16": 64, "17": 50, "18": 35, "19": 42, "2": 42, "20": 50, "21": 64, "22": 57, "23": 57, "3": 42, "4": 42, "5": 42, "6": 21, "7": 28, "8": 50, "9": 71}, "Thursday": {"0": 78, "1": 50, "10": 21, "11": 28, "12": 35, "13": 35, "14": 35, "15": 50, "16": 50, "17": 42, "18": 28, "19": 14, "2": 57, "20": 21, "21": 42, "22": 85, "23": 64, "3": 57, "4": 50, "5": 71, "6": 78, "7": 57, "8": 42, "9": 28}, "Tuesday": {"0": 50, "1": 57, "10": 28, "11": 50, "12": 71, "13": 64, "14": 50, "15": 35, "16": 35, "17": 50, "18": 64, "19": 64, "2": 78, "20": 64, "21": 57, "22": 64, "23": 50, "3": 92, "4": 92, "5": 50, "6": 35, "7": 35, "8": 21, "9": 28}, "Wednesday": {"0": 35, "1": 35, "10": 14, "11": 28, "12": 64, "13": 92, "14": 92, "15": 85, "16": 78, "17": 42, "18": 28, "19": 21, "2": 28, "20": 28, "21": 42, "22": 42, "23": 57, "3": 35, "4": 35, "5": 21, "6": 21, "7": 21, "8": 21, "9": 14}}'::jsonb, NULL, ARRAY['Sports complex'], NULL, '00:00', '23:59') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('NANA PICKLEBALL', '01 Phan Tứ, Bắc Mỹ An, Ngũ Hành Sơn, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Bắc Mỹ An, Ngu Hanh Son', 16.045348, 108.240834, 3.9, 15, '+84 986 087 817', 'https://www.google.com/maps/place/NANA+PICKLEBALL/data=!4m7!3m6!1s0x314217002efa18e3:0xff48c1b4b75a368c!8m2!3d16.0453479!4d108.2408338!16s%2Fg%2F11w33r_9mh!19sChIJ4xj6LgAXQjERjDZat7TBSP8?authuser=0&hl=en&rclk=1', NULL, 'ChIJ4xj6LgAXQjERjDZat7TBSP8', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGtPnFxLf52mTu4z3ChI7qdZ7Azlab870af05jHSIfz4KoAIk28rAnYyO-U6_AYJKyrqPftbx7_n4imJrPNS6L0QZOsQgAbp0FS7HbGt0210faf2i65ftA2MQf1wuH26EEJ3s592IIYp5CC=w408-h305-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGtPnFxLf52mTu4z3ChI7qdZ7Azlab870af05jHSIfz4KoAIk28rAnYyO-U6_AYJKyrqPftbx7_n4imJrPNS6L0QZOsQgAbp0FS7HbGt0210faf2i65ftA2MQf1wuH26EEJ3s592IIYp5CC=w397-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEvB-bgKG2z9atyNrTL3X78kTmgGJXtvcVxeE3lXhsYDFsFYEj3a5DNKUK592zgJiq2uArUp7eCAXjR-kgfeZWTD8pAv1uP9Exq9P5sCfA1yTPpLRRIbwLipbPiN7R3moJrkj9vHd3UZkW8=w224-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=vH0MqU6mFlKbCUVMviNsgw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=339.79987&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["Open 24 hours"], "Monday": ["Open 24 hours"], "Saturday": ["Open 24 hours"], "Sunday": ["Open 24 hours"], "Thursday": ["Open 24 hours"], "Tuesday": ["Open 24 hours"], "Wednesday": ["Open 24 hours"]}'::jsonb, '[{"Name": "Tom G.", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXeSvLrVtEBK0ss4Qj5L8aRLkXzjqMNdLi2OE5rWVocgunnfx9HoQ=s120-c-rp-mo-ba4-br100", "Rating": 2, "Description": "There are so many courts in Đà Nẵng now but nana is not competitive anymore. The court is not maintained very well and old guys smoking indoors at night.\n\nI think social price needs to drop to 25k ( courtyard is 50k + water, wet towel and fruit and the court is much nicer).\n\nNow we have TBE and HERA closeby with much better courts and environment.\nRiverpoint social = 25k.\n\nCourt price with 120k /h during the day is also too expensive. Duy King and G4 = 80k /h with better courts.\n\nThe most positive about nana is the morning staff with Tiến being very friendly and welcoming to guest s.", "Images": null, "When": ""}, {"Name": "Sophie Ann", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLfcXX0quCYjKlfuM5XqRhCkkp2OO4slGIqTCJS9jne7Sa2kw=s120-c-rp-mo-ba5-br100", "Rating": 2, "Description": "1. Super hot in the court. No fans is provided. They hide them all the time, taking away from the court.  Closed room without any air inside at all.\n2. If you book your court ypu will fing another ppl playing on your court 5-10 minutes of your paid time. But manager does nothing about it at all.\n3.ppl walking front and back or making pictures on your booked court while u trying to play. But manager does nothing about it at all.\n4. The bigger surprise will waiting for you when 1 of the staff will start to smoke cigarettes inside the closed court with no fresh air inside it", "Images": null, "When": ""}, {"Name": "Adam Neilson", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVcFVjn60gRssniZQNok3dxJc0xv74_kaCoR9oF73p73efRPcPT=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Great pickleball courts - nicely shaded as indoors, but with windows open for a breeze.\nOnly 120k/hour and an extra 20k per paddle.", "Images": null, "When": ""}, {"Name": "Bing Yu", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjX4TTPpcjOKkFO7k-v6pwwg1VW2K1bRNbdzZcCeixKxupINVL3d=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Excellent pickleball courts with 3 indoor  and 1 outdoor. We played in 2 and spent 120k vnd per hour with rackets and balls included. It’s the best one among the 3 pickleball places I’ve been to in da nang. The owner is very friendly and welcoming! I’ve been playing twice there and will certainly come back!", "Images": null, "When": ""}, {"Name": "Alessandro Vitro", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXwncyeuxw98FIvJQRGVpeooIRWCbzHYz8uZ5yG8S8Sh1V4m6SH=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "They have the best courts (we tried 3 others) and it''s even good price. It''s a pity nobody knows it but at the same time I''m happy I always find an available court to play.", "Images": null, "When": ""}, {"Name": "Patrick Desranleau", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVKUojsAP6YJPJcNNTqMyVoxuW3Gzf_YJkAYaqWDMVa6Fr5vQ68=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "Try to get some information but the guy at the reception was not interested and I never took is eyes off is phone", "Images": null, "When": ""}, {"Name": "phuong nk", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUwUwbcWCuA9SVcaduB_VRaEjEwFF8SAT04xZxaNSm6lH62abKE=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Good", "Images": null, "When": ""}, {"Name": "ky le", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUKumFsfLJ6KTMQMgEkAp34y8Kphsgl1vEwA_kN41gNruw3IXdv=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Sân đã được sửa chữa mới rộng rãi, thái độ nhân viên tốt, thân thiện, giá rẻ nhất trong khu vực", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3clfgWF5cvEjggtcsPRGQEXtCOcISuwyYvumZI8igb5mHcesw9B4JZPd7r091BLp6bN4Z5h9n33FA1Nlmsz8W7qvFFDCONwGJ0VOgVnNTiTNjI9oBwx6eIvzstA90hQYpHEjs3=k-no"], "When": "2024-11-23"}]'::jsonb, '{"Friday": {"0": 46, "1": 62, "10": 34, "11": 28, "12": 21, "13": 21, "14": 37, "15": 59, "16": 65, "17": 68, "18": 68, "19": 65, "2": 46, "20": 50, "21": 40, "22": 31, "23": 34, "3": 40, "