INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Pickleball Thuỷ Lợi Hội An', '24 Phan Bá Phiến, Tân An, Hội An Tây, Đà Nẵng, Vietnam', 'Da Nang', 'Tân An, Hoi An Tay', 15.88754, 108.322803, 5.0, 15, '+84 905 799 569', 'https://www.google.com/maps/place/Pickleball+Thu%E1%BB%B7+L%E1%BB%A3i+H%E1%BB%99i+An/data=!4m7!3m6!1s0x31420f00174461f7:0x993b5230008d8862!8m2!3d15.8875398!4d108.3228032!16s%2Fg%2F11x13hvfz6!19sChIJ92FEFwAPQjERYoiNADBSO5k?authuser=0&hl=en&rclk=1', NULL, 'ChIJ92FEFwAPQjERYoiNADBSO5k', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAF2_bcM1J2qWUZi4N3y_qXpdID-qJ6cj092OlVsNmt3_KNCqHL56AUscXrIXDO4aaPfezitX-fakquZlrNamZ-KugCpAwdca6jhiJGJgIg4kRynH_QVOK4PquTPLj0hW5FTLqQ-yVtxJJ31=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAF2_bcM1J2qWUZi4N3y_qXpdID-qJ6cj092OlVsNmt3_KNCqHL56AUscXrIXDO4aaPfezitX-fakquZlrNamZ-KugCpAwdca6jhiJGJgIg4kRynH_QVOK4PquTPLj0hW5FTLqQ-yVtxJJ31=w397-h298-k-no"}, {"title": "Stadium", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGcqhoPs1gwSolIvdU0yMsCgt_9lLsmxZqePlC8duxUFfXnxZphiSVVtuE_p9O-95z-apGamOv722LTimuIWeqaKP0SO0FedKCYqNWiUzxTMAfXYaTZ9PEjQ4rZogmlEj3nYkK4JTCxIlhA=w224-h298-k-no"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Allen Williams", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXd2Z4ymQvwgaYNEv_ZVnEWD1yb302xFlVYyMqYQ7ArcasBGAPG=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place to go to and play. I came early and was trying to see if anyone was willing to play. The local worker said that he would play with me and we played for a bit. Good games full court and skinny singles. The facilities are shaded and good prices to rent a court. I will be back.  Highly recommend!!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1VfZ16YqummG6t7WWHMnDNvrTQhraQC1bXNkcLjWe8kMjHlhCwe6TBZME--vISBhVndcQwok4PvLApoVwT-1ait8kyCJGGdopHE-i6Mx6cIN7JXm_UPi6QRYnV6-FF9smQu9eTwQ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0Dfmxk5fjcTTszts7-U6LXviXDC4oaEdEOt5IJjpP5uQe84a-5TB2zpWVR5e2XcwWhX6Ej0jUCE_225KudWJC4KK_XhDXXeOgOnHpl4cRzJlTHjP25JeeSoClXl_mZ354OZ68=k-no"], "When": "2025-3-25"}, {"Name": "Christine Rose", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIpZqw1K2DoxMC26n_WJknixZSABZHVsw5OWqpSsAPAvHZRGA=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "What a wonderful place to play pickleball, great surface and under cover. Floodlights for play in evenings. Our friend who lives in Hoi An invited us,we had a brilliant time.  Friendly people and you can hire paddles.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2BqE7j1eVMbPFfwYnZ0b1Pr5riAqpp8z3-QYKelFoZf_RCGTQtxBPOM4slQukTUlumv0zOnLVriXzT8GllYEIFcX_ex0lKMaSAVxCAd36i2kEw1keqojDdp8HFwPPCHVTcoao=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3AhJOw8kQcj6lbMLFrp18U87pp_IAbUDbIv-BlSPg7sm7wMorsJE8dOERltlGAW89H-s7olnK0rz6F1HowmqSrUCwvn9TNfIFvWuQxXuI7DliK4vvJdYUEMl9VKopd_UKPtanb=k-no"], "When": "2025-3-26"}, {"Name": "Jay See", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUiNHL9gtNYvcIyBf9Z8DbpYS0BakX1AxXPfN-OPkkf4W3cItul-w=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Second trip to Hoi An but first time playing pickleball here. Very nice courts which opened in Feb 2025 (1 month old when I visited). Spacing between courts is generous, all 6 courts are clean and there is an option to open or close the roof. As it was a Thursday afternoon, it wasn''t busy until 4-5pm onwards. Another selling point - it was inexpensive as it was VND 100k for the hour I played excluding paddles and balls (extra 50k).\nWould happily come back and play another game, you will be looked after by Bao!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn15rp3_UAi8U5bQpBKSSX1G5IE_B-BixunkF5VRv1Pr8O1mhAlNuPnkZpYtXJTj3Y4uPHaNE_xFWZsY5oK96dk1VJySMLMxfiUjxxvnsLiMEQd4BAUGu_3qCty2by0q-0qkxTeX9w=k-no"], "When": "2025-3-29"}, {"Name": "Freddie castagna", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLo4aoIgHKN9W7z2bSiWXRA3NrKdzMkseczkev5XwsX1dTFig=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place really nice courts and friendly workers", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn02xbNUrI2qmwNy_nuaTDXaK5IefzXf_AizAEzH96R9MIXI_KdS2ta_oidnwHdgLg8moRg1dKDsOmwLDWQJhI9Cz7QQjIyiU0WHQ4r5j3aBPzHxm0dD74_LaoATarnVUxUjGBvUyQ=k-no"], "When": "2025-4-3"}, {"Name": "Evo''s Challenges Evo", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU7FQKSmHbpFd5UG4Py-JxYU0XIKkOM2IxYi38EWARsM1OKpDXS=s120-c-rp-mo-br100", "Rating": 5, "Description": "Loads of fun.\nFriendly staff..", "Images": null, "When": ""}, {"Name": "Tuấn Tăng", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWkEbn5OOfqGtvMLU-d1jsbz3UXC33jIQ0wWjwtj-Jp-Gk8e6HpeA=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Sân chơi cho người đam mê", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2lBzz8KiQ8IYrwGnnhRAk0CZM-oRDZ5ovQvJGV0RCImFA2U-D-s9taVDM2_lggkgVtktND5rx9GVHmK2OMDufepFFpk30URfHdos0Ot47AKUu1vwhV7RZfjul6XWK9oN0-Yp4obXjrWq6M=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3F0Ab-TME_T_McmnnAIWtOdxrfuPg1A1a9hNE6MM9ho7gUDYl5wpbFS-XZ0eJsNqJ0ISKHKu8OTuD-wHgyHYfHgswckLqu9IL_y2wyvm3rUk3Lx7ULZttSbN_sIfzMAUhMbi2jUlspktbi=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3wnJ-9M1HqXf6vBMhM2i0UghEsd0IotlKQHCOFexRmFQEFo2U0Md_kmM6menixahjKdyymQNaswbsnutP5f6imTnMKDimq5Ec2wkmHe7r_eF8zSadAa_qHjNfdBKitA-6oIrmHV_TObQ_C=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2KDERCmuwfR-wxXXu6Tikz2SKXvEjie_86QstuKXrBJj89wLazuy9J